/*
 * electronic_load.ino — DIY Electronic Load (Constant Current)
 *
 * Elements:
 *   1. MOSFET CC Load Stage + MCP4725 DAC (I²C 0x60) — gate control
 *   2. INA219 (I²C 0x40)                             — actual I + V
 *   3. SSD1306 OLED (I²C 0x3C)                       — live display
 *   4. Rotary Encoder KY-040                          — setpoint
 *   5. Arduino Nano 3.0                               — orchestrator
 *
 * Load formula: I_set_mA = DAC_code × 3300 / 4095 / 100  [mA]
 * (0.1 Ω sense, op-amp drives MOSFET to maintain V_sense = V_dac)
 */

#include <Wire.h>
#include <Adafruit_INA219.h>
#include <Adafruit_SSD1306.h>
#include <Adafruit_MCP4725.h>

// --- Pins ---
#define ENC_CLK   2
#define ENC_DT    4
#define ENC_SW    3
#define FAN_PIN   7
#define NTC_PIN  A0

// --- Constants ---
#define I_MAX_MA   5000
#define I_STEP_MA    50
#define I_STEP_COARSE 500
#define OTP_C         80.0f
#define DAC_RSHUNT   100.0f   // 0.1 Ω × 1000 = 100 mΩ denominator
#define VREF_MV     3300.0f

// --- Objects ---
Adafruit_INA219   ina;
Adafruit_SSD1306  oled(128, 64, &Wire, -1);
Adafruit_MCP4725  dac;

// --- State ---
int     setpoint_ma  = 0;
bool    load_on      = false;
float   energy_wh    = 0.0f;

volatile int  enc_d  = 0;
volatile bool enc_p  = false;
void ICACHE_RAM_ATTR isr_clk() { enc_d += digitalRead(ENC_DT) ? -1 : 1; }
void ICACHE_RAM_ATTR isr_sw()  { enc_p  = true; }

uint16_t ma_to_dac(int ma) {
  // V_sense = I × R_shunt = ma × 0.001 × 0.1 = ma × 0.0001 V
  // DAC_code = V_sense / VREF × 4096 = ma × 0.0001 / 3.3 × 4096
  return (uint16_t)constrain((long)ma * 4096 / (long)(VREF_MV / 0.1f), 0, 4095);
}

float read_ntc_c() {
  int raw = analogRead(NTC_PIN);
  // Simplified Steinhart-Hart for 10k NTC at 25 °C
  float r = 10000.0f * raw / (1023.0f - raw);
  float t = 1.0f / (log(r / 10000.0f) / 3950.0f + 1.0f / 298.15f) - 273.15f;
  return t;
}

void update_oled(float act_ma, float volt_v, float pow_w) {
  oled.clearDisplay();
  oled.setTextSize(1); oled.setTextColor(SSD1306_WHITE);
  oled.setCursor(0,  0); oled.printf("Set:  %4d mA", setpoint_ma);
  oled.setCursor(0, 12); oled.printf("I:  %6.1f mA", act_ma);
  oled.setCursor(0, 24); oled.printf("V:   %5.3f V",  volt_v);
  oled.setCursor(0, 36); oled.printf("P:   %5.2f W  %.3f Wh", pow_w, energy_wh);
  oled.setCursor(0, 52); oled.print(load_on ? "LOAD ON " : "LOAD OFF");
  oled.display();
}

void setup() {
  Serial.begin(115200);
  Wire.begin();

  ina.begin();
  oled.begin(SSD1306_SWITCHCAPVCC, 0x3C);
  oled.clearDisplay(); oled.display();
  dac.begin(0x60);
  dac.setVoltage(0, false);  // DAC = 0 → load off

  pinMode(FAN_PIN, OUTPUT); digitalWrite(FAN_PIN, LOW);
  pinMode(ENC_CLK, INPUT_PULLUP); pinMode(ENC_DT, INPUT_PULLUP); pinMode(ENC_SW, INPUT_PULLUP);
  attachInterrupt(digitalPinToInterrupt(ENC_CLK), isr_clk, FALLING);
  attachInterrupt(digitalPinToInterrupt(ENC_SW),  isr_sw,  FALLING);

  Serial.println(F("Electronic load ready."));
}

void loop() {
  static unsigned long last_read  = 0;
  static unsigned long last_disp  = 0;

  unsigned long now = millis();

  // --- Encoder ---
  noInterrupts(); int d = enc_d; enc_d = 0; bool p = enc_p; enc_p = false; interrupts();
  if (d != 0) {
    setpoint_ma = constrain(setpoint_ma + d * I_STEP_MA, 0, I_MAX_MA);
    if (load_on) dac.setVoltage(ma_to_dac(setpoint_ma), false);
  }
  if (p) {
    load_on = !load_on;
    dac.setVoltage(load_on ? ma_to_dac(setpoint_ma) : 0, false);
    if (!load_on) energy_wh = 0.0f;  // reset on load-off
  }

  // --- INA219 at 20 Hz ---
  if (now - last_read >= 50UL) {
    float dt_h = (now - last_read) / 3600000.0f;
    last_read = now;

    float act_ma = ina.getCurrent_mA();
    float volt_v = ina.getBusVoltage_V();
    float pow_w  = volt_v * act_ma / 1000.0f;
    energy_wh   += pow_w * dt_h;

    // OTP protection
    float ntc_c = read_ntc_c();
    digitalWrite(FAN_PIN, ntc_c > 50.0f ? HIGH : LOW);
    if (ntc_c > OTP_C && load_on) {
      setpoint_ma = setpoint_ma / 2;
      dac.setVoltage(ma_to_dac(setpoint_ma), false);
      Serial.printf("OTP! %.1f C — load halved to %d mA\n", ntc_c, setpoint_ma);
    }

    // OLED at 4 Hz
    if (now - last_disp >= 250UL) {
      last_disp = now;
      update_oled(act_ma, volt_v, pow_w);
      Serial.printf("Set=%d Act=%.1f V=%.3f P=%.2f\n", setpoint_ma, act_ma, volt_v, pow_w);
    }
  }
}
